from flask import Flask, request, jsonify
import numpy as np
import face_recognition
import os
import pickle

app = Flask(__name__)

# Load employee photos and encode them
def load_employee_photos(directory):
    known_encodings = []
    known_names = []
    for filename in os.listdir(directory):
        if filename.endswith('.jpg') or filename.endswith('.png'):
            image = face_recognition.load_image_file(os.path.join(directory, filename))
            encoding = face_recognition.face_encodings(image)[0]
            known_encodings.append(encoding)
            known_names.append(os.path.splitext(filename)[0])  # Use filename as name
    return known_encodings, known_names

# Load the employee data
known_encodings, known_names = load_employee_photos('employee_photos')

@app.route('/recognize', methods=['POST'])
def recognize_face():
    image_file = request.files['image']
    image = face_recognition.load_image_file(image_file)
    face_encodings = face_recognition.face_encodings(image)
    
    if not face_encodings:
        return jsonify({"error": "No face found in the image."}), 400

    face_encoding = face_encodings[0]
    distances = face_recognition.face_distance(known_encodings, face_encoding)
    probabilities = 1 - distances
    
    recognition_results = {}
    for name, prob in zip(known_names, probabilities):
        recognition_results[name] = float(prob)

    return jsonify(recognition_results)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)